def apply_thyroid_protocol(
    tsh_value: float,
    tsh_date: str,
    ft4_value: float,
    ft4_date: str,
    patient_id: str
) -> str:
    """
    Apply thyroid function protocol based on TSH and FT4 values.
    Returns a summary string with findings and recommended action.
    """
    # Build report components
    report_parts = []

    # TSH report
    if tsh_value is not None and tsh_date is not None:
        report_parts.append(f"The most recent TSH value for patient {patient_id} is {tsh_value} uIU/mL from {tsh_date}.")
    elif tsh_value is not None:
        report_parts.append(f"The most recent TSH value for patient {patient_id} is {tsh_value} uIU/mL.")
    else:
        report_parts.append(f"No TSH result was found for patient {patient_id}.")

    # FT4 report
    if ft4_value is not None and ft4_date is not None:
        report_parts.append(f"The most recent free T4 (FT4) value is {ft4_value} from {ft4_date}.")
    elif ft4_value is not None:
        report_parts.append(f"The most recent free T4 (FT4) value is {ft4_value}.")
    else:
        report_parts.append("The most recent free T4 (FT4) result was not found.")

    # Apply protocol
    if tsh_value is not None:
        if tsh_value > 10:
            action = "CRITICAL ALERT: TSH is elevated above 10 uIU/mL. Immediate clinical attention required."
            if ft4_value is not None and ft4_value < 0.7:
                action += " Low FT4 suggests primary hypothyroidism."
        elif 4.5 <= tsh_value <= 10:
            action = "FLAG FOR REVIEW: TSH is between 4.5 and 10 uIU/mL, indicating possible subclinical hypothyroidism."
        else:
            action = "No action required per protocol. TSH is within normal range."
    else:
        action = "No action required per protocol. TSH result is not available."

    report_parts.append(action)
    return " ".join(report_parts)

